import { unstable_cache } from 'next/cache';
import { revalidateTag } from 'next/cache';
import { redirect } from 'next/navigation';
import { getAllProducts } from '@/lib/db';
import styles from './page.module.css';

// ---------- Cached catalog data ----------
// Tagged with "products" so it can be invalidated from anywhere
// that uses the same tag.  Fallback TTL of 5 min means the
// catalog also refreshes periodically on its own.

const getCachedProducts = unstable_cache(
  async () => {
    const products = await getAllProducts();
    return products;
  },
  ['admin-products-list'],
  { tags: ['products'], revalidate: 300 },
);

// The page is dynamic so every request re-renders, but the
// PRODUCT DATA comes from the cache above — no repeated queries.
export const dynamic = 'force-dynamic';

// ---------- Page ----------

export default async function AdminProductsPage(props: {
  searchParams: Promise<{ synced?: string }>;
}) {
  const searchParams = await props.searchParams;
  const products = await getCachedProducts();

  // ---- Inline Server Action ----
  // A regular HTML form posts to this action.  It invalidates the
  // "products" cache tag and redirects back so the page re-renders
  // with fresh data.  The action returns immediately — the
  // revalidation is async from the caller's perspective.

  async function syncCatalog() {
    'use server';
    // Second argument controls the stale window during background
    // revalidation — serve briefly stale data for up to 60 s
    // while the new catalog is computed, then expire.
    revalidateTag('products', { expire: 60 });

    // Redirect back with a query param so the page can show a
    // confirmation banner.  The redirect causes a full re-render,
    // at which point the cache tag has already been invalidated
    // and getCachedProducts will fetch fresh data.
    redirect('/admin/products?synced=1');
  }

  const justSynced = searchParams.synced === '1';

  // ---- Render ----

  return (
    <div className={styles.container}>
      <div className={styles.header}>
        <div>
          <h1 className={styles.title}>Product Catalog</h1>
          <p className={styles.subtitle}>
            Browse and sync product data from your ERP/PIM system.
          </p>
        </div>

        {/* Regular HTML form — no client JS needed to submit. */}
        <form action={syncCatalog} className={styles.syncForm}>
          <button type="submit" className={styles.syncButton}>
            &#x21bb;&nbsp; Sync Latest Catalog
