import { headers } from 'next/headers';
import Link from 'next/link';
import type { Metadata } from 'next';
import type { UserAgentPageProps } from '@/lib/blog-types';
import { getRecentPosts } from '@/lib/blog-data';

export const metadata: Metadata = {
  title: 'Home',
  description: 'Welcome to my blog homepage',
  openGraph: {
    title: 'Home - My Blog',
  },
};

export const dynamic = 'force-dynamic';

export default async function HomePage() {
  const requestHeaders = await headers();
  const userAgent = requestHeaders.get('user-agent') ?? '';
  const posts = await getRecentPosts(5);
  const props: UserAgentPageProps = {
    timestamp: new Date().toISOString(),
    userAgent,
    posts,
  };

  return (
    <div>
      <h1>Welcome to My Blog</h1>
      <p>Server-side rendered at: {props.timestamp}</p>
      <p>Your user agent: {props.userAgent}</p>

      <h2>Recent Posts</h2>
      <ul>
        {props.posts.map((post) => (
          <li key={post.id}>
            <Link href={`/blog/${post.id}`}>{post.title}</Link>
          </li>
        ))}
      </ul>

      <Link href="/blog" className="button-link">
        View All Posts
      </Link>
    </div>
  );
}

